from difflib import SequenceMatcher

def detect_duplicate_contexts(agent):
    def wrapped_run(*args, **kwargs):
        result = agent.run(*args, **kwargs)
        contexts = agent.memory.get('retrieval_context', [])
        texts = [ctx['text'] for ctx in contexts]

        duplicates = 0
        for i in range(len(texts)):
            for j in range(i+1, len(texts)):
                similarity = SequenceMatcher(None, texts[i], texts[j]).ratio()
                if similarity > 0.85:
                    duplicates += 1

        if duplicates > 0:
            print(f'⚠️ {duplicates} duplicate contexts detected')
        return result
    agent.run = wrapped_run
    return agent
